noncompliant:
double f64a = 1.0, f64b = 2.0;
float f32a = 1.0f, f32b = 2.0f;
int32_t s32a = 10, s32b = 5;
uint16_t u16a = 100, u16b = 200;
uint8_t u8a = 10, u8b = 20;
int16_t s16a = 100, s16b = 200;

// Noncompliant examples:
float result1 = (float)(f64a + f64b);        // Widening cast
double result2 = (double)(f32a + f32b);      // Signedness change
double result3 = (double)(s32a / s32b);      // Type change
uint32_t result4 = (uint32_t)(u16a + u16b);  // Widening cast
uint16_t result5 = (uint16_t)(u8a * u8b);    // Promotion then cast
int32_t result6 = (int32_t)(s16a * s16b);    // Widening cast

// More noncompliant examples
uint16_t result7 = (uint16_t)(f64a + f64b);   // Type category change
float result8 = (float)(u16a + u16b);         // Type category change

compliant:
double f64a = 1.0, f64b = 2.0;
float f32a = 1.0f, f32b = 2.0f;
int32_t s32a = 10, s32b = 5;
uint16_t u16a = 100, u16b = 200;
uint8_t u8a = 10, u8b = 20;
int16_t s16a = 100, s16b = 200;

// Compliant examples:
float temp1 = (float)f64a;
float result1 = temp1 + (float)f64b;         // Cast individual operands

float result2 = f32a + f32b;                 // No cast needed

int32_t temp2 = s32a / s32b;
int16_t result3 = (int16_t)temp2;            // Narrowing same signedness

uint32_t temp3 = (uint32_t)u16a + (uint32_t)u16b;
uint16_t result4 = (uint16_t)temp3;          // Explicit temporary

// Using intermediate variables for clarity
double expr_result = f64a + f64b;
float final_result = (float)expr_result;     // Cast simple expression

// Direct assignment without complex casting
int32_t simple_result = s32a + s32b;         // No cast needed
